const supportedReportTypes = ['overall', 'inventory', 'menu', 'payroll', 'projection'];
const requestedReportType = $json.body?.reportType ?? $json.reportType ?? 'overall';
const reportType = supportedReportTypes.includes(requestedReportType)
  ? requestedReportType
  : 'overall';

return [
  {
    json: {
      reportType,
      requestedReportType,
      debug: {
        step: 'validate-report-type',
        supportedReportTypes,
        usedFallbackReportType: reportType !== requestedReportType
      }
    }
  }
];

const fs = require('fs');
const path = require('path');

const dataDir = '/home/node/data';
const files = {
  sales: 'sales.csv',
  inventory: 'inventory.csv',
  menuItems: 'menu_items.csv',
  payroll: 'payroll.csv',
  expenses: 'expenses.csv',
  settings: 'settings.csv'
};

const parseValue = (value) => {
  const trimmed = String(value ?? '').trim();
  if (!trimmed) {
    return '';
  }

  const numericValue = Number(trimmed);
  return Number.isNaN(numericValue) ? trimmed : numericValue;
};

const parseCsvLine = (line) => {
  const cells = [];
  let current = '';
  let inQuotes = false;

  for (let index = 0; index < line.length; index += 1) {
    const char = line[index];
    const nextChar = line[index + 1];

    if (char === '"' && inQuotes && nextChar === '"') {
      current += '"';
      index += 1;
      continue;
    }

    if (char === '"') {
      inQuotes = !inQuotes;
      continue;
    }

    if (char === ',' && !inQuotes) {
      cells.push(current);
      current = '';
      continue;
    }

    current += char;
  }

  cells.push(current);
  return cells;
};

const readCsv = (fileName) => {
  const filePath = path.join(dataDir, fileName);
  const content = fs.readFileSync(filePath, 'utf8').trim();
  const [headerLine, ...rows] = content.split(/\r?\n/).filter(Boolean);
  const headers = parseCsvLine(headerLine);

  return rows.map((row) => {
    const cells = parseCsvLine(row);
    return Object.fromEntries(
      headers.map((header, index) => [header, parseValue(cells[index])])
    );
  });
};

const csvData = {};
const recordCounts = {};

for (const [key, fileName] of Object.entries(files)) {
  csvData[key] = readCsv(fileName);
  recordCounts[key] = csvData[key].length;
}

return [
  {
    json: {
      ...$json,
      csvData,
      debug: {
        ...$json.debug,
        step: 'load-csv-data',
        dataDir,
        recordCounts
      }
    }
  }
];

const data = $json.csvData;

const sum = (rows, key) =>
  rows.reduce((total, row) => total + (Number(row[key]) || 0), 0);

const groupSum = (rows, groupKey, valueKey) =>
  rows.reduce((groups, row) => {
    const group = row[groupKey] || 'Unknown';
    groups[group] = (groups[group] || 0) + (Number(row[valueKey]) || 0);
    return groups;
  }, {});

const topEntry = (groups) =>
  Object.entries(groups).sort(([, valueA], [, valueB]) => valueB - valueA)[0] ?? ['N/A', 0];

const settingValue = (metric, fallback) => {
  const setting = data.settings.find((item) => item.metric === metric);
  return setting ? setting.value : fallback;
};

const totalRevenue = sum(data.sales, 'revenue');
const quantitySold = sum(data.sales, 'quantity_sold');
const [topMenuItem, topMenuItemRevenue] = topEntry(groupSum(data.sales, 'menu_item', 'revenue'));

const inventoryRisks = data.inventory
  .map((item) => {
    const currentStock = Number(item.current_stock) || 0;
    const dailyUsage = Number(item.daily_usage) || 0;
    const reorderLevel = Number(item.reorder_level) || 0;
    const daysLeft = dailyUsage > 0 ? currentStock / dailyUsage : null;

    return {
      item: item.item,
      category: item.category,
      currentStock,
      unit: item.unit,
      dailyUsage,
      reorderLevel,
      supplier: item.supplier,
      daysLeft
    };
  })
  .filter((item) => item.currentStock <= item.reorderLevel)
  .sort((a, b) => (a.daysLeft ?? 999) - (b.daysLeft ?? 999));

const menuMarginRisks = data.menuItems
  .map((item) => {
    const sellingPrice = Number(item.selling_price) || 0;
    const foodCost = Number(item.food_cost) || 0;
    const targetMargin = Number(item.target_margin) || 0;
    const margin = sellingPrice > 0 ? ((sellingPrice - foodCost) / sellingPrice) * 100 : 0;

    return {
      menuItem: item.menu_item,
      category: item.category,
      sellingPrice,
      foodCost,
      targetMargin,
      margin,
      salesVolume: Number(item.sales_volume) || 0
    };
  })
  .filter((item) => item.margin < item.targetMargin)
  .sort((a, b) => b.salesVolume - a.salesVolume);

const totalGrossPayroll = sum(data.payroll, 'gross_pay');
const totalNetPayroll = sum(data.payroll, 'net_pay');
const overtimePay = sum(data.payroll, 'ot_pay');
const totalExpenses = sum(data.expenses, 'amount');
const payrollPercent = totalRevenue > 0 ? (totalGrossPayroll / totalRevenue) * 100 : 0;
const expensePercent = totalRevenue > 0 ? (totalExpenses / totalRevenue) * 100 : 0;
const estimatedProfit = totalRevenue - totalExpenses - totalGrossPayroll;

const metrics = {
  branch: settingValue('primary_branch', 'Quezon City'),
  currency: settingValue('currency', 'PHP'),
  totalRevenue,
  quantitySold,
  topMenuItem,
  topMenuItemRevenue,
  inventoryRisks,
  menuMarginRisks,
  totalGrossPayroll,
  totalNetPayroll,
  overtimePay,
  totalExpenses,
  payrollPercent,
  expensePercent,
  estimatedProfit,
  targetPayrollMinPercent: Number(settingValue('target_payroll_min_percent', 22)),
  targetPayrollMaxPercent: Number(settingValue('target_payroll_max_percent', 26)),
  targetFoodCostPercent: Number(settingValue('target_food_cost_percent', 32))
};

return [
  {
    json: {
      ...$json,
      metrics,
      debug: {
        ...$json.debug,
        step: 'calculate-poc-metrics',
        calculatedAt: new Date().toISOString()
      }
    }
  }
];

const peso = new Intl.NumberFormat('en-PH', {
  style: 'currency',
  currency: 'PHP',
  maximumFractionDigits: 0
});

const percent = (value) => `${Number(value).toFixed(1)}%`;
const listItems = (items, selector, fallback) =>
  items.length > 0 ? items.map(selector).join('\n') : fallback;

const metrics = $json.metrics;
const inventoryList = listItems(
  metrics.inventoryRisks.slice(0, 4),
  (item) => `- ${item.item}: ${item.currentStock} ${item.unit} left, reorder level ${item.reorderLevel} ${item.unit}, supplier ${item.supplier}`,
  '- No inventory item is currently below reorder level.'
);
const menuRiskList = listItems(
  metrics.menuMarginRisks.slice(0, 4),
  (item) => `- ${item.menuItem}: margin ${percent(item.margin)} vs target ${percent(item.targetMargin)}, sales volume ${item.salesVolume}`,
  '- No menu item is below target margin in the sample data.'
);

const reports = {
  overall: `Overall AI Report\n\n${metrics.branch} generated ${peso.format(metrics.totalRevenue)} from ${metrics.quantitySold} units sold in the sample CSV data. Estimated profit after payroll and listed expenses is ${peso.format(metrics.estimatedProfit)}.\n\nKey risks:\n${inventoryList}\n${menuRiskList}\n\nRecommended next step: prioritize critical inventory replenishment, then review menu pricing and weekday staffing before adding live AI generation.`,
  inventory: `Inventory Report\n\nThe CSV inventory file shows ${metrics.inventoryRisks.length} items at or below reorder level.\n\nItems to review:\n${inventoryList}\n\nRecommended next step: confirm supplier lead times and reorder quantities before the next dinner or delivery peak.`,
  menu: `Menu Pricing Report\n\nTop revenue item from sales CSV: ${metrics.topMenuItem} at ${peso.format(metrics.topMenuItemRevenue)}.\n\nMargin risks:\n${menuRiskList}\n\nRecommended next step: adjust high-volume low-margin items before discounting or running promos.`,
  payroll: `Payroll Report\n\nGross payroll is ${peso.format(metrics.totalGrossPayroll)}, net payroll is ${peso.format(metrics.totalNetPayroll)}, and overtime pay is ${peso.format(metrics.overtimePay)}. Payroll is ${percent(metrics.payrollPercent)} of sample revenue versus the target range of ${percent(metrics.targetPayrollMinPercent)} to ${percent(metrics.targetPayrollMaxPercent)}.\n\nRecommended next step: review overtime and slower weekday staffing before publishing the next roster.`,
  projection: `Business Projection Report\n\nSample revenue is ${peso.format(metrics.totalRevenue)}, listed expenses are ${peso.format(metrics.totalExpenses)}, and estimated profit is ${peso.format(metrics.estimatedProfit)}. Expenses are ${percent(metrics.expensePercent)} of revenue before payroll adjustments.\n\nRecommended next step: rerun this after the next CSV refresh, then compare estimated profit against the frontend dashboard projection.`
};

return [
  {
    json: {
      success: true,
      reportType: $json.reportType,
      generatedAt: new Date().toISOString(),
      report: reports[$json.reportType]
    }
  }
];
